  "typescriptCustomType": "class MountainArray {
    __secret: number[];
    __N: number;
    __guesses: number;
    constructor(secret: number[]) {
        this.__secret = secret;
        this.__N = secret.length;
        this.__guesses = 100;
    }

    get(index: number): number {
        this.__guesses -= 1;
        return this.__secret[index];
    }

    getGuesses(): number {
        return this.__guesses;
    }

    length(): number {
        return this.__N;
    }
};
